  "FINISH": {
   "name": "FINISH",
   "file": "verbs.zil",
   "line": 77,
   "endLine": 105,
   "source": "<ROUTINE FINISH (\"OPTIONAL\" (REPEATING <>))\n\t <CRLF>\n\t <COND (<NOT .REPEATING>\n\t\t<V-SCORE>\n\t\t<CRLF>)>\n\t <TELL\n\"Would you like to start over, restore a saved position, get hints or end this session of the game?|\n(Type RESTART, RESTORE, HINTS or QUIT):|>\">\n\t <PUTB ,P-INBUF 1 0>\n\t <READ ,P-INBUF ,P-LEXV>\n\t <COND (<EQUAL? <GET ,P-LEXV 1> ,W?RESTART>\n\t        <RESTART>\n\t\t<TELL \"Failed.\" CR>\n\t\t<FINISH T>)\n\t       (<EQUAL? <GET ,P-LEXV 1> ,W?RESTORE>\n\t\t<COND (<RESTORE>\n\t\t       <TELL \"Ok.\" CR>)\n\t\t      (T\n\t\t       <TELL \"Failed.\" CR>\n\t\t       <FINISH T>)>)\n\t       (<EQUAL? <GET ,P-LEXV 1> ,W?HINTS>\n\t\t<V-HINTS>\n\t\t<INIT-STATUS-LINE>\n\t\t<UPDATE-STATUS-LINE>\n\t\t<FINISH T>)\n\t       (<EQUAL? <GET ,P-LEXV 1> ,W?QUIT ,W?Q>\n\t\t<QUIT>)\n\t       (T\n\t\t<FINISH T>)>>"
  },
