  "V-SCORE": {
   "name": "V-SCORE",
   "file": "verbs.zil",
   "line": 137,
   "endLine": 153,
   "source": "<ROUTINE V-SCORE (\"OPTIONAL\" (ASK? T))\n\t <COND (<L? ,SCORE 400>\n\t\t<TELL\n\"We are about to give you your score. Put on your peril-sensitive sunglasses\nnow. (Hit RETURN or ENTER when ready.) \">\n\t\t<PRINTI \">\">\n\t\t<PUTB ,P-INBUF 1 0>\n\t\t<READ ,P-INBUF ,P-LEXV>\n\t\t<SETG P-CONT <>>\n\t\t<CRLF>)>\n\t <TELL \"Your score is \" N ,SCORE \" of a possible 400, in \" N ,MOVES>\n\t <COND (<1? ,MOVES>\n\t\t<TELL \" turn.\">)\n\t       (T\n\t\t<TELL \" turns.\">)>\n\t <CRLF>\n\t ,SCORE>"
  },
